    pub fn new(
        inner: Arc<dyn AuditSink>,
        allowlist: Vec<String>,
        writer: Arc<V2AuditWriter>,
        run_id: impl Into<String>,
        session_id: impl Into<String>,
    ) -> Self {
        Self {
            inner,
            allowlist,
            writer,
